import{_ as a,o as e,c as r,ag as i}from"./chunks/framework.DEqXEGcv.js";const m=JSON.parse('{"title":"Internationalization & Mirror Acceleration","description":"","frontmatter":{},"headers":[],"relativePath":"en/docs/guide/i18n.md","filePath":"en/docs/guide/i18n.md"}'),o={name:"en/docs/guide/i18n.md"};function n(d,t,c,s,l,u){return e(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="internationalization-mirror-acceleration" tabindex="-1">Internationalization &amp; Mirror Acceleration <a class="header-anchor" href="#internationalization-mirror-acceleration" aria-label="Permalink to &quot;Internationalization &amp; Mirror Acceleration&quot;">​</a></h1><p>RDE supports multi-language UI and provides one-click domestic mirror source acceleration for Chinese users.</p><h2 id="language-support" tabindex="-1">Language Support <a class="header-anchor" href="#language-support" aria-label="Permalink to &quot;Language Support&quot;">​</a></h2><p>Currently supported:</p><ul><li>🇨🇳 Simplified Chinese (<code>zh-CN</code>)</li><li>🇺🇸 English (<code>en-US</code>)</li></ul><p>Switch in &quot;System Settings&quot; → &quot;Language&quot;.</p><h2 id="domestic-mirror-source-acceleration" tabindex="-1">Domestic Mirror Source Acceleration <a class="header-anchor" href="#domestic-mirror-source-acceleration" aria-label="Permalink to &quot;Domestic Mirror Source Acceleration&quot;">​</a></h2><p>When Chinese is selected, RDE automatically recommends and enables domestic mirror sources covering:</p><table tabindex="0"><thead><tr><th>Source</th><th>Description</th></tr></thead><tbody><tr><td>APT</td><td>Debian/Ubuntu package management</td></tr><tr><td>Docker</td><td>Docker Hub images</td></tr><tr><td>NPM</td><td>Node.js package management</td></tr><tr><td>PIP</td><td>Python package management</td></tr><tr><td>Flatpak</td><td>Flatpak app repository</td></tr><tr><td>Go</td><td>Go Modules proxy</td></tr><tr><td>Cargo</td><td>Rust package management</td></tr><tr><td>GitHub</td><td>GitHub file acceleration</td></tr><tr><td>Maven</td><td>Java dependency management</td></tr></tbody></table><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><h3 id="master-switch" tabindex="-1">Master Switch <a class="header-anchor" href="#master-switch" aria-label="Permalink to &quot;Master Switch&quot;">​</a></h3><ul><li><strong>Enable</strong>: Switch all sources to domestic mirrors at once</li><li><strong>Disable</strong>: Restore to official sources</li></ul><h3 id="individual-customization" tabindex="-1">Individual Customization <a class="header-anchor" href="#individual-customization" aria-label="Permalink to &quot;Individual Customization&quot;">​</a></h3><p>Expand to configure each source independently:</p><ul><li>Choose specific mirror provider (Alibaba Cloud, Tencent Cloud, Tsinghua TUNA, etc.)</li><li>Or use a custom mirror URL</li></ul><h3 id="first-run-wizard" tabindex="-1">First-Run Wizard <a class="header-anchor" href="#first-run-wizard" aria-label="Permalink to &quot;First-Run Wizard&quot;">​</a></h3><p>The last step of the setup wizard prompts mirror source configuration, which can be changed later in settings.</p>',17)])])}const p=a(o,[["render",n]]);export{m as __pageData,p as default};
